config.script:
draft = self.view.custom.editDraft or {}
meta  = draft.get('meta') or {}
if meta.get('Id') is None:
	BlueRidge.Common.Notify.toast('No template selected', 'Pick one from the list first.', 'warning')
	return
result = BlueRidge.Parts.OperationTemplate.update(meta)
BlueRidge.Common.Ui.notifyResult(result, 'Template saved')
if result and result.get('Status'):
	refreshed = BlueRidge.Parts.OperationTemplate.getOne(meta.get('Id'))
	if refreshed is not None:
		self.view.custom.selected  = {'meta': dict(refreshed)}
		self.view.custom.editDraft = {'meta': dict(refreshed)}
	system.perspective.sendMessage('templateListRefresh', scope='page')

meta = (self.view.custom.selected or {}).get('meta') or {}
templateId = meta.get('Id')
if templateId is None:
	return
result = BlueRidge.Parts.OperationTemplate.createNewVersion(templateId)
BlueRidge.Common.Ui.notifyResult(result, 'New version created')
if result and result.get('Status'):
	newId = result.get('NewId')
	system.perspective.sendMessage('templateListRefresh', scope='page')
	if newId:
		system.perspective.sendMessage('templateSelectId', payload={'id': newId}, scope='page')

customMethods.script:
meta = (self.view.custom.selected or {}).get('meta') or {}
templateId = meta.get('Id')
if templateId is None:
	return
self.loadFields()

meta = (self.view.custom.selected or {}).get('meta') or {}
templateId = meta.get('Id')
if templateId is None:
	empty = {'rows': []}
	self.view.custom.fieldsState = {'selected': dict(empty), 'editDraft': dict(empty)}
	return
instances = BlueRidge.Parts.OperationTemplate.getFieldsForTemplate(templateId) or []
loaded = []
for inst in instances:
	f = (inst or {}).get('field') or {}
	loaded.append({
		'id':                    f.get('Id'),
		'dataCollectionFieldId': f.get('DataCollectionFieldId'),
		'code':                  f.get('Code') or '',
		'name':                  f.get('Name') or '',
		'isRequired':            bool(f.get('IsRequired')),
	})
self.view.custom.fieldsState = {'selected': {'rows': loaded}, 'editDraft': {'rows': [dict(r) for r in loaded]}}

meta = (self.view.custom.selected or {}).get('meta') or {}
templateId = meta.get('Id')
if templateId is None:
	BlueRidge.Common.Notify.toast('No template selected', 'Pick a template before saving.', 'warning')
	return
draft = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.fieldsState.editDraft) or {}
rows = draft.get('rows') or []
result = BlueRidge.Parts.OperationTemplate.saveFieldsAll(templateId, rows)
BlueRidge.Common.Ui.notifyResult(result, 'Fields saved')
if result and result.get('Status'):
	self.loadFields()

draft = dict(BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.fieldsState.editDraft) or {'rows': []})
rows = list(draft.get('rows') or [])
rows.append({
	'id':                    None,
	'dataCollectionFieldId': None,
	'code':                  '',
	'name':                  '',
	'isRequired':            True,
})
draft['rows'] = rows
selected = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.fieldsState.selected) or {'rows': []}
self.view.custom.fieldsState = {'selected': selected, 'editDraft': draft}

