messageHandlers.script:
action = (payload or {}).get('action')
pendingId = self.view.custom.pendingNav
self.view.custom.pendingNav = None
if pendingId is None:
	return
if action == 'cancel':
	# Revert the version dropdown to the currently-selected template.
	currentId = ((self.view.custom.selected or {}).get('meta') or {}).get('Id') or 0
	self.view.custom.selectedVersionId = currentId
	return
if action == 'save':
	draft = self.view.custom.editDraft or {}
	meta  = draft.get('meta') or {}
	if meta.get('Id') is not None:
		result = BlueRidge.Parts.OperationTemplate.update(meta)
		BlueRidge.Common.Ui.notifyResult(result, 'Template saved')
	if self.view.custom.fieldsDirty:
		self.handleSaveFields()
self._loadTemplate(pendingId)

action = (payload or {}).get('action')
if action != 'confirm':
	return
meta = (self.view.custom.selected or {}).get('meta') or {}
templateId = meta.get('Id')
if templateId is None:
	return
result = BlueRidge.Parts.OperationTemplate.deprecate(templateId)
BlueRidge.Common.Ui.notifyResult(result, 'Template deprecated')
if result and result.get('Status'):
	self.view.custom.selected  = {'meta': None}
	self.view.custom.editDraft = {'meta': None}
	self.view.custom.mode = 'view'
	self.view.custom.selectedTemplateCode = ''
	self.view.custom.selectedVersionId    = 0
	self.view.custom.fieldsState = {"selected": {"rows": []}, "editDraft": {"rows": []}}
	system.perspective.sendMessage('templateListRefresh', scope='page')
